const startedAt = new Date().toISOString();
const source = $input.first().json;
const files = source.files || source.body?.files || [];
const pr = source.pr || source.body?.pr || null;
const missingVars = [];
if (!$env.TELEGRAM_BOT_TOKEN) missingVars.push("TELEGRAM_BOT_TOKEN");
if (!$env.TELEGRAM_CHAT_ID) missingVars.push("TELEGRAM_CHAT_ID");
if (missingVars.length > 0) throw new Error("Pre-hook FAIL: " + missingVars.join(", "));
const out = { files, pr, startedAt, contextOk: true, workflow: "linkedin-antiban-review" };
return [{ json: out }];

const ctx = $input.first().json;
const files = ctx.files || [];
const PAT = ["browser","playwright","stealth","fingerprint","timing","delay","session","humanDelay","inputBlock","clickLocator","inviteWorker","inboxWorker","organicContent","syncSearch","syncList","sendInvites","sendMessages"];
const QUESTIONS = ["1. Cambia comportamento browser su LinkedIn?","2. Cambia timing, delay o ordine delle azioni?","3. Tocca fingerprint, stealth, cookie o sessione?","4. Aggiunge azioni LinkedIn (click, navigazione, typing)?","5. Cambia volumi, budget, cap o limiti?"];
const flagged = files.filter(f => PAT.some(p => (f||"").toLowerCase().includes(p.toLowerCase())));
const verdict = flagged.length > 0 ? "REVIEW" : "SAFE";
const out = { files, flaggedFiles: flagged, hasSensitiveFiles: flagged.length > 0, verdict, checklist: flagged.length > 0 ? QUESTIONS : [], pr: ctx.pr, startedAt: ctx.startedAt, workflow: ctx.workflow };
return [{ json: out }];

const data = $input.first().json;
const flagged = data.flaggedFiles || [];
const lines = ["⚠️ *Antiban Review: REVIEW RICHIESTA*","","*File sensibili rilevati (" + flagged.length + "):*"];
flagged.forEach(f => lines.push("  • "));
lines.push("");
lines.push("*Checklist anti-ban obbligatoria:*");
(data.checklist || []).forEach(q => lines.push("  " + q));
lines.push("");
lines.push("*Azione richiesta:* esegui /antiban-review prima di procedere.");
lines.push("*Verdetto:* " + data.verdict);
if (data.pr) lines.push("*PR/Branch:* " + data.pr);
lines.push("_" + data.startedAt + "_");
const out = { report: lines.join("
"), verdict: data.verdict, flaggedFiles: flagged, startedAt: data.startedAt };
return [{ json: out }];

const prev = $input.first().json;
const log = { workflow:"linkedin-antiban-review", verdict: prev.verdict||"SAFE", flaggedFiles: prev.flaggedFiles||[], loggedAt: new Date().toISOString() };
console.log("[POST-HOOK antiban-review]", JSON.stringify(log));
return [{ json: log }];
